(269, 148, 'وضع اللمسات الأخيرة على ترتيبات النقل والتسليم وتوزيع الملابس على قرية الأيتام.', 'Finalize arrangements for transportation, delivery, and distribution of clothing to the orphan village.', 197, '2022-07-28', '10:15:00', '2024-03-25 23:30:00', '2024-03-25 23:30:00', NULL),
(270, 149, 'اتصل بالمانحين المحتملين وتأمين الالتزامات للتبرعات بملابس العيد', 'Contact potential donors and secure commitments for Eid clothing donations', 197, '2024-03-20', '11:00:00', '2024-04-02 13:59:03', '2024-04-02 13:59:03', NULL),
(271, 149, 'إدارة حملات وسائل التواصل الاجتماعي والنشرات الإخبارية عبر البريد الإلكتروني للترويج للحملة', 'Manage social media campaigns and email newsletters to promote the campaign', 200, '2024-03-20', '11:00:00', '2024-04-02 14:00:05', '2024-04-02 14:00:31', NULL),
(272, 149, 'تنظيم الخدمات اللوجستية لشراء وتوزيع ملابس العيد على الأطفال الأيتام', 'Organize logistics for purchasing and distributing Eid clothes to orphaned children', 197, '2024-03-20', '11:00:00', '2024-04-02 14:02:07', '2024-04-02 14:02:07', NULL),
(273, 149, 'تطوير مواد ترويجية مثل النشرات والملصقات والرسومات عبر الإنترنت', 'Develop promotional materials such as flyers, posters, and online graphics', 197, '2024-03-20', '11:00:00', '2024-04-02 14:03:26', '2024-04-02 14:03:26', NULL),
(274, 150, 'المتابعة مع الجهات المانحة المحتملة وتقديم آخر المستجدات بشأن التقدم المحرز', 'Follow up with potential donors and provide updates on progress', 199, '2024-03-17', '11:00:00', '2024-04-05 19:15:56', '2024-04-05 19:15:56', NULL),
(275, 150, 'وضع اللمسات الأخيرة على خطط لجمع التبرعات الأحداث وتنسيق الخدمات اللوجستية مع أصحاب المصلحة المعنيين.', 'Finalize plans for fundraising events and coordinate logistics with relevant stakeholders.', 197, '2024-03-17', '11:00:00', '2024-04-05 19:17:02', '2024-04-05 19:17:02', NULL),
(276, 150, 'معالجة أي قضايا أو مخاوف معلقة أثيرت خلال الاجتماع وتقديم الدعم حسب الحاجة.', 'Address any outstanding issues or concerns raised during the meeting and provide support as needed.', 200, '2024-03-17', '11:00:00', '2024-04-05 19:18:52', '2024-04-05 19:18:52', NULL),
