(106, 'super', 'admin', 'superadmin@newegypt.com', '$2y$12$vhM.sFtc5FBlQQAuZQtjwOP/UkXkKXFjh5M35b8qJ2vYdb4Stf5nK', '01276593926', '000000', 'cairo', 'Web Developer', NULL, '2023-08-06', 'This article deals with formulating a suitable title and an appropriate abstract for an original research paper. The “title” and the “abstract” are the “initial impressions” of a research article, and hence they need to be drafted correctly, accurately, carefully, and meticulously. Often both of these are drafted after the full manuscript is ready. Most readers read only the title and the abstract of a research paper and very few will go on to read the full paper. The title and the abstract are the most important parts of a research paper and should be pleasant to read. The “title” should be descriptive, direct, accurate, appropriate, interesting, concise, precise, unique, and should not be misleading. The “abstract” needs to be simple, specific, clear, unbiased, honest, concise, precise, stand-alone, complete, scholarly, (preferably) structured, and should not be misrepresentative.', 'cee714f7bc4974e36a76c24d5475f899.png', NULL, NULL, NULL, 'https://twitter.com/Mahmoud17272776?t=2FpfjATUp_vilBdrG-C_Bg&s=35', 'https://twitter.com/Mahmoud17272776?t=2FpfjATUp_vilBdrG-C_Bg&s=35', 'https://www.instagram.com/mahmod.ayman99/', NULL, 'https://www.instagram.com/mahmod.ayman99/', '2022-05-15 12:23:09', 1, 0, NULL, NULL, 'Africa/Cairo', NULL, '2026-01-08 12:09:24', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
(161, 'admin', 'admin', 'egyptionwomenclub@admin.com', '$2a$12$4kDvm58eApvYd8v3thPC4.44KaY6l6JA7mqbU1yPj2.SI9Nk6Mx5G', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2022-08-22 13:30:51', 3, 0, NULL, NULL, 'America/New_York', NULL, '2025-10-17 12:23:51', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
(192, 'د.منى طنطاوي', 'Dr. Mona Tantawy', 'drtantawi@gmail.com', '$2y$10$vZr6pksY/p10oSFj0XXneOIZBfccPdw6EJ23Lw8odtiVaVj0d1tXa', '+1 (201) 424-4251', NULL, NULL, ' President – IEW Club (New Egypt Group Division)', NULL, NULL, 'I\'m  the founder of Hackensack Pediatrics with over 40 years of pediatric \r\nexperience.\r\nI graduated from Cairo University School of Medicine in Egypt in 1972.\r\nI received My M.D. degree at age 23. Then I went on to complete my pediatric \r\nresidency at the University of Medicine and Dentistry of New Jersey with the honor \r\nof being offered the Chief Resident position in only her 3rd year.\r\nBoard certified and a fellow of the American Academy of Pediatrics, I began my\r\ncareer as the Chief of out-patient pediatrics at Hackensack University Medical Center taking the honor of being the first full-time female pediatrician ever hired by the hospital. \r\nAfter seven years of devoted service,  then I started my own private practice (Hackensack Pediatrics)\r\nin 1985 and going strong ever since. Currently holds an academic appointment as clinical assistant professor at UMDNJ and as an instructor at New York Medical College. I enjoy teaching medical students and residents.\r\npresident of Egyptian American Medical Association (EAMA) for two years. Several fundraisers to support building a hospital for the underprivileged in Egypt in collaboration with MAAN , provided financial support for cochlear implants for children in Egypt, and supported forty Egyptian medical students to seek residency training in the United States.', '5150a32e690959fb7d887a29b0d3151b.jpg', NULL, NULL, NULL, 'https://www.facebook.com/drtantawi', NULL, NULL, NULL, NULL, '2023-01-15 06:18:28', 2, 0, NULL, NULL, 'Africa/Cairo', '2022-08-10 11:09:46', '2024-04-07 14:44:46', NULL, NULL, NULL, 'cWnqEO8zEU0jkN3R-Dhld5:APA91bEKyug-MWQ6CW38urLOStQbEpLVSdYmYoX8lDYRaQhMF-oRCBz-ggTzB38T7XvUeK6YYWC23SAa3UJWuQpiE0LCAk7BuQkxDjBjBbKtTS9Xavl3s0JAZ2-oGZjRrwlEUvtdMuot', 'iOS', NULL, 0, NULL, NULL, NULL, 1),
(193, 'د.غادة علي', 'Dr.Ghada Ali', 'ghada.m.ali@foc.cu.edu.eg', '$2y$10$vZr6pksY/p10oSFj0XXneOIZBfccPdw6EJ23Lw8odtiVaVj0d1tXa', '01002406126', NULL, NULL, 'New Egypt Regional Director Middel Easte & Egypt', NULL, NULL, 'I\'m a member of parliament for the Coordination of Youth Parties and Politicians. PhD in risk management and insurance from Cairo University. A member of the Advisory Committee for Institutional Development and Investment at the Ministry of Youth and Sports. Additionally,  The Deputy Director of the Anti-Harassment and Violence Against Women Unit at Cairo University. Responsible for raising awareness of combating violence against women at the level of students and university administrators. I\'m one of the founders of the Network of Arab Universities to Combat Violence against Women under the auspices of the Arab Women Organization of the League of Arab States. Deputy Director of the Professional Master\'s and Doctorate Unit at Cairo University.\r\nI\'m an expert on women\'s empowerment and a member of the Gender-Based Violence Network .I led an initiative to teach girls self-defense mechanisms against harassment, in cooperation with the Police Sports Federation. I done many TV episodes and press interviews to empower women and combat harassment and violence against women. I also organized 10 camps for university students and 10 workshops for the university.', 'd17a1d57644e42c524fe6396efb0f2fa.jpg', NULL, NULL, NULL, 'https://www.facebook.com/Drghada1', NULL, NULL, NULL, NULL, '2023-01-15 06:25:00', 4, 0, NULL, NULL, NULL, '2022-08-10 11:16:53', '2022-08-17 09:28:42', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
(194, 'كريستينا رافائيل', 'Christina Raphael', 'christinasraphael@gmail.com', '$2y$12$inDYZDMnLpkRvQ37yANz5OenohspTZVL7hQwxX1dobPkklnkYVax2', '+1 (201) 844-0342', NULL, NULL, 'Security Officer – New Egypt Group', NULL, NULL, NULL, '797791bd75c4dde1c6435fb30de8b76a.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2023-08-15 01:32:05', 2, 0, NULL, NULL, 'Africa/Cairo', '2022-08-10 11:21:57', '2025-11-05 23:56:37', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
(197, 'ماجد أمين', 'Maged Amin', 'amin@flyallover.com', '$2y$12$KjnLMgVztdh7jFNaYFsRmuafEIMYKwBSIppz/O1pNw5CrTfMgyrGS', '+1 718-415-1618', NULL, NULL, ' Vice President – New Egypt Group / Founder of IEW Club & IEY Club', NULL, NULL, 'I am an entrepreneur who started my career as an accountant in 1992. I earned my degree in Accounting and Financial Management from Alexandria University, Egypt. In 1995, I moved to the US.\r\nAs a member of the Arabic and Egyptian community, I was the one who suggested, created and donated the website for the Egyptian Consulate in New York. I was also one of the first people who introduced online journalism to the Arabic community.\r\nI am currently the owner of Fly Allover tourism company based in Brooklyn, NY.\r\nIn 2011, after the Egyptian revolution I felt the social gap between the American and Egyptian communities and decided to do something about it. I established New Egypt Group to work as the link that connects the two societies. \r\n\r\nI’m the founder and I serve as the current Vice President for New Egypt Inc. a non-profit Organization ©. I saw the urgent need for establishing a T.V channel to be able to network the services that New Egypt offers to the community and to build the bridge between the two communities.\r\n\r\nAs an entrepreneur, I recruited young, doctors, engineers, dietitians, educators and lawyers from the American Egyptian community to improve their skills and help them help their communities through NE TV*. \r\n\r\nNew Egypt was the core for many important international clubs and non-profit organizations that serve various communities. I’m the Co-founder for International Egyptian Women Club. on April 2018 I start my new project FLY ALL OVER.', '1c7d40e5d5b6e425b9a2dc1b6883af0b.jpg', NULL, NULL, NULL, 'https://www.facebook.com/magedamin1973', 'https://twitter.com/?lang=en', 'https://www.instagram.com/maged.amin/', 'https://www.reddit.com/', 'https://www.linkedin.com/in/maged-amin-26083765/', '2023-01-15 06:23:12', 2, 0, NULL, NULL, 'Africa/Cairo', '2022-08-10 12:48:36', '2025-11-12 13:26:43', NULL, NULL, NULL, 'jhdgfgshjvkljslfklvdfjvkljdfk', 'samsung', NULL, 0, NULL, NULL, NULL, 1),
