(220, 'مصطفى أغا', 'Mostafa Agha', 'eng.m.agha98@gmail.com', '$2y$10$vZr6pksY/p10oSFj0XXneOIZBfccPdw6EJ23Lw8odtiVaVj0d1tXa', '+79774420684', NULL, NULL, 'Executive Board member', NULL, NULL, NULL, '914b234cbf7f6e3c3d243398fc64966d.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2023-08-15 04:00:54', 4, 0, NULL, NULL, NULL, '2022-08-12 19:01:14', '2022-08-12 19:01:14', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
(233, NULL, 'محمود ايمن', 'xghfh325255@gmail.com', NULL, '012547896325', NULL, 'dvbfsgvbfgv', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 8, 0, 'SDAFED', '3IEShIgFiI85fzRO5rXFfWxTnNTXPJ0Alt5Vy9rcJkdoi5XL83Nh0woAlwV9u5KPaIbWDPNfiVCxHCSaHVskDy7WkVCQfzipbfpc', NULL, '2022-08-14 08:03:40', '2022-08-22 11:24:15', '2023-07-02 06:17:32', NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
(238, 'نسيم مجدي', 'Niseem Magdy', 'niseemm@gmail.com', '$2y$10$vZr6pksY/p10oSFj0XXneOIZBfccPdw6EJ23Lw8odtiVaVj0d1tXa', '+13614168500', NULL, NULL, NULL, NULL, NULL, 'Research Associate at the State University of New York at Stony Brook\r\nHe received his Bachelor of Science degree in physics from AL-AZHAR University in Cairo. Then he joined the Brookhaven National Laboratory as a visiting scientist in 2014. In 2018 he received his Ph.D. degree from the State University of New York at Stony Brook. Then, he was a post-doctor research assistant in the physics department at the University of Illinois at Chicago from 2018 to 2022. Currently, he is a research associate at the State University of New York at Stony Brook.  His current work is focused on studying the strongly interacting medium (Quark-Gluon Plasma) which is a liquid that exists at an extremely high temperature and/or density. It is believed that up to a few milliseconds after the Big Bang, the universe was in a quark-gluon plasma state.', '74a55141ebd6f12f3e773294641fc93c.jpg', NULL, NULL, NULL, 'https://www.facebook.com/profile.php?id=100077126295655', NULL, NULL, NULL, NULL, '2023-08-15 01:44:01', 1, 0, NULL, NULL, NULL, '2022-08-15 09:17:48', '2022-08-15 09:17:48', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
(240, NULL, 'Abdelwareth-Mohammed', 'a.mohmmedss2050@gmail.com', NULL, '01221257027', 'undefined', 'qena', NULL, NULL, NULL, NULL, '539245f3f1b2fcb6c7c5f75f0bf9bdb9.PNG', '55959cf6145bcd985e6eacadbc3d89d3.PNG', '4413a29aa90af0b1467787859eada3b3.PNG', '53a2425fa91b20d24116c7a275a5e7d6.PNG', NULL, NULL, NULL, NULL, NULL, NULL, 8, 0, 'hnfhbfghfh', 'gXMdGglvtJWRM5EGn7x6AbW6rcQTDPAaNaX2FTOUkIeWhcs4k6yzjPUFvqBtgzHcc50C6aUkVBQcYjbWp3Mh7KxLdx4WvePtQoGP', NULL, '2022-08-16 10:12:39', '2022-08-16 10:20:58', '2023-07-02 06:17:32', NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
(241, 'ياسمين إبراهيم', 'Yasmeen Ibrahim', 'yai2102@columbia.edu', '$2y$10$vZr6pksY/p10oSFj0XXneOIZBfccPdw6EJ23Lw8odtiVaVj0d1tXa', '7039814845', NULL, NULL, 'Executive Board member', NULL, NULL, 'I\'m an Egyptian American creative entrepreneur and mental health advocate. At the age of 18, I founded an international beauty and styling business based out of Washington DC and was part of an Emmy award winning team with CNN. later I went on to study psychology and business management at Columbia University in New York and graduated magna cum laude. Using my business background and passion for psychology, I currently work to improve the organizational culture and employee experience for various clients.', '8b4a2387ec3425d82dccf14bfaa8b2e3.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2023-08-15 04:04:06', 1, 0, NULL, NULL, NULL, '2022-08-17 14:13:31', '2022-08-17 14:13:31', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
