(882, 'زين العابدين محمود احمد عارف', 'زين العابدين محمود احمد عارف', 'z.alrefai90@gmail.com', '$2y$10$5p.cy/Q6im1vw4DW43eefuDNIR6bydT9IFkFB7teZj.eMI.b8pUky', '01102040500', '29006192701691', 'قنا -قوص -حجازة', 'معلم', '34', '1990-06-19', 'زين العابدين محمود احمد \r\nحاصل علي بكالوريوس علوم زراعية \r\nمعلم بوزارة التربية والتعليم \r\nحاصل علي دورات الاستراتيجية والأمن القومي وإدارة الأزمات باكاديمية ناصر العسكرية العليا \r\nمدير تنفيذي متطوع بجمعية الرفاعي للتنمية الإنسانية \r\nمتطوع بمؤسسة حياة كريمة\r\nمتطوع بجمعية الاورمان في توزيع كراتين المواد الغذائية ولحوم الاضاحي \r\nالمشاركة فى عمل وحدة الغسيل الكلوي بقريتنا بالجهود الذاتية \r\nالمشاركة في انشاء معهد رفاعة الابتدائي الأزهري بالجهود الذاتية \r\nالمشاركة فى انشاء وحدة إسعاف بالجهود الذاتية \r\nالمشاركة فى حملات التبرع بالدم لعمل رصيد لصالح الحالات الطارئة  الخاصة بقريتنا ببنك الدم الإقليمي بمحافظتي قنا والاقصر \r\nالمشاركة فى عمل ندوات توعية بجائحة كورونا وجلسات دعم نفسي للحالات المرضية', '3794349222660953d422fa6b95ea9a9a.jpg', NULL, NULL, NULL, 'https://www.facebook.com/zien.alabdienalrefae?mibextid=ZbWKwL', NULL, 'https://www.instagram.com/zien.alabdienalrefae?igsh=MTYxc2w3Y2QxaGltZw==', NULL, NULL, '2024-03-12 21:59:07', 6, 0, NULL, NULL, 'Africa/Cairo', '2024-03-12 20:46:37', '2024-03-20 19:07:40', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
