(951, NULL, 'يسرا خالد عبدالهادي السيد ماجد', NULL, '$2y$10$zEDXJYyO8v7dLhcHs5HmJ.NmtgQP.p3aSRytJgALEGXr.mxLZhY/m', '01099997475', '29607183100085', 'ش الجمهورية أمام معسكر الشباب سفاجا البحر الاحمر', 'Quality monitoring executive', '27', NULL, NULL, '8c6c2aa271f992683dade109dfb20c49.jpeg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-03-13 15:23:33', 6, 0, NULL, NULL, 'America/New_York', '2024-03-13 15:23:12', '2024-03-16 00:02:54', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
