(978, NULL, 'MOHAMMED MAHMOUD', NULL, '$2y$10$xKhKXDZVODJjh9JQOQah/.RNYnVpTyocjQSLSADNuA6MRg5ERlwIm', '01220034971', NULL, 'Ismalila', 'طالب', '21', NULL, NULL, '97c42f6c57c98bdc4adb04f35dac8f09.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-03-15 20:59:44', 6, 0, NULL, NULL, NULL, '2024-03-14 14:45:15', '2024-03-15 21:00:14', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
(979, NULL, 'أسماء البدري محمد زيدان', NULL, NULL, '01090669458', NULL, 'علم الروم', 'مقدم إذاعة ومقدم مؤتمرات', '٢١', NULL, NULL, '548ef7c63b1800377f9178644b11a1dc.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 6, 0, NULL, 'aBtLsLSfJSxrTsPbdAS9CRLLyost5WCJ2ZG9ZdNZGrpcuU508zePUkHunJMOyoNIq3WYmTVTSCSkAGzUpFzqiixofgSkbcllMITS', NULL, '2024-03-14 14:50:22', '2024-03-15 14:01:17', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
(980, 'Doaa ABDO', 'Doaa ABDO', NULL, '$2y$10$TGNS0MwCNUucD27ZhSPO4uKAE/jNyb8oNh/mQP2vcglwrHl/66Mp2', '01019766707', '28501103300309', 'Matrouh', 'Trainer', '39', '1985-01-10', 'مدرب   TOT معتمد بالأكاديمية المهنية للمعلمين اعتبارا من 27/7 2023 ولمدة 3 سنوات .\r\n معلم أول دراسات أجتماعية من 2006 .\r\n مدرب برابطة المدربين العرب .\r\nمدربة تعليم مدنى  ومهارات مجتمعية – وزارة الشباب والرياضة ومنظمة اليونيسيف.\r\nمدرب ريادة أعمال  ومهارات حياتية تابع لشركة قدرة .\r\nأستشارى تدريب ومنسق مشروعات بشركة قدرة بالمشروع القومى للنهوض بمهارات الشباب تحت شعار (مهارتك أساس مهنتك) التابع لوزارة القوى العاملة بالتعاون مع برنامج الاغذية العالمى   wfbوشركة قدرة\r\nمدربة تنمية مجتمعية بالمركز العربى الاوربى للشباب والتنمية .\r\nمدربة بصندوق مكافحة الادمان والتعاطى  _مجلس الوزراء. \r\nمدربة محليات تابعة لوزارة التضامن الاجتماعى بالتعاون مع وزارة الشباب والرياضة والتنمية المحلية (مشروع مستقبلنا في أيدينا ).\r\nمدربة علاقات أسرية بوزارة التضامن الاجتماعى  مشروع مودة .\r\nمدرب توعية سياسية  تابع للمركز المصرى لحقوق المرأة .\r\nمنسق لمشروع أصوات النساء التابع للمركز المصرى لحقوق المرأة .\r\nمنسق مشروع قيم وحياة التابع لمؤسسة \r\nأجيال مصر لمدة أربعة سنوات\r\n\r\n:الدورات الحاصلة عليها \r\nحاصلة على برنامج الدبلوم المهنى ( القيادة التربوية والامن القومى ) والذى عقدت بلاكاديمية العسكرية المصرية بمقرها الحالى بالكلية الحربية فى الفترة من 13/ 5/2023 الى 26/10/2023م فى أطار المبادرة الرئاسية لأعداد 1000معلم من شباب المعلمين  المرشحين أن يصبحوا مديرين للمدارس وفق بروتوكول التعاون بين وزارة التربية والتعليم والتعليم الفنى وكلية التربية جامعة حلوان وبالتعاون مع الاكاديمية العسكرية المصرية .\r\nالمشاركة كمدرب فى البرنامج التدريبى للتنمية المهنية لمعلمين الدراسات الاجتماعية للصف الخامس الابتدائى  بقاعة الاجتماعات بديوان مديرية التربية والتعليم يوم الاحد الموافق 19 / 2 /2023م\r\nحاصلة على الدورة التدريبية للتنمية المهنية لمعلمى الدراسات الاجتماعية 2.0  للفصل الدراسى الثانى 2022/2023 م خلال الفترة من 7 الى 9 فبراير 2023 م  بالمدينة التعليمية بالسادس من اكتوبر .\r\nحاصلة على برنامج تثقيف الاقران لحملة 360 التابعة للجمعية المصرية لتنظيم الاسرة بالتعاون مع شبكة تثقيف الاقران y-peer  خلال الفترة من 10 الى 13 ديسمبر 2022م\r\nالمشاركة في قمة coy17  بشرم الشيخ في الفترة من 2 الى 4 نوفمبر 2022 م تابعة وممثلة عن برنامج تصدوا معانا التابع لوزارة الشباب والرياضة .\r\nحاصلة على البرنامج التدريبى لرفع كفاءة الكوادر البرلمانية خلال الفترة من 27 الى 30 يونيو 2022\r\nحاصلة على الدورة التدريبية في ريادة الاعمال التابعة للوكالة الاسبانية بالتعاون مع وزارة الشباب والرياضة ومؤسسة كير مصر للتنمية وميكروسوفت مصر في الفترة من 11يونيو 2022 الى 25 يونيو 2022م \r\n\r\nحاصلة على الدورة التثقيفية الخاصة بالهجرة الغير شرعية تحت شعار مصر في عيون أبنائها خلال الفترة من 16 الى 19 أكتوبر 2021 م التابعة لحزب الشعب الجمهورى .\r\n\r\nحاصلة على دورة أعداد المدربين المتقدمة ضمن البرنامج القومى لمواجهة الشائعات وتأثيرها على الامن القومى تحت شعار (تصدوا معنا )التابع لوزارة الشباب والرياضة خلال الفترة من 10 الى 19 نوفمبر 2020م بمركز التعليم المدنى بالجزيرة بالقاهرة .\r\nحاصلة على دورة تدريبية بعنوان ورشة عمل التوعية الماليه والمعرفية البنكية بمحافظة مطروح خلال الفترة من 13 الى 14 سبتمبر 2020م بمقدار12 ساعة تدريبية \r\n\r\nحاصلة على  ورشة تدريب المدربين لاعداد الكوادر الشبابية للمشروع القومى للحفاظ على كيان الاسرة المصرية التابع لوزارة التضامن الاجتماعى بالتعاون مع وزارة الشباب والرياضة وصندوق الامم المتحدة للسكان ووكالة التعاون الكندية  فى الفترة من 17 الى 19 فبراير 2020 م\r\n\r\nحاصلة على دورة أدارة الازمات والتفاوض الاستثنائية رقم (3 ) لصالح وزارة الشباب والرياضة المنعقدة بكلية الدفاع الجوى في الفترة من 20/1/2018 م الى 31/1 /2018 م\r\n\r\nحاصلة على الدورة التثقيفية للدراسات الاستراتيجية والامن القومى رقم (29 ) المنعقدة بكلية الدفاع الوطنى وأكاديمية ناصر العسكرية في الفترة من 4/3 /2017 الى 16 /3 /2017م\r\n\r\nالمشاركة كمدربة بالمعسكر التدريبى الأول للشباب بأبو قير لتأهيل شباب الأحزاب للمحليات في الفترة من 7الى 11 مارس 2017 م\r\nحاصلةعلى برنامج دعم الجمعيات والمؤسسات الاهلية لتمكين الشباب من المشاركة الفعالة فى المحليات والعمل العام (مستقبلنا فى أيدينا ) المرحلة الاولى فى الفترة من 26 الى 30 أبريل لعام 2015 م  بمدينة 6 أكتوبر  ,والمرحلة الثانية فى الفترة من 28 مايو الى 2 يونيو 2015 م بمدينة الاسكندرية بالتعاون بين وزارة التضامن الاجتماعى ووزارة الشباب والرياضة ووزارة التمية المحلية ومؤسسة أجيال وبيت الخبرة البرلمانى .\r\nالمشاركه فى البرنامج التدريبى عن المساءله المجتمعيه التابع لجمعيه أجيال واعده فى الفتره من 2/10 ألى 4/10 /2015م \r\nحاصلة على  الدوره التدريبيه التابعه للمركزالمصرى لحقوق المرأه عن تمكين القيادات الشابه لخوض أنتخابات المجلس المحلى فى الفتره من 7 /9 الى 10 /9 /2015م\r\nحاصلة على دورة  تدريبية في ادارة الحملات الانتخابية للمرأة المصرية بمدينة سفاجا بمحافظة البحر الاحمر فى الفترة من 6 الى 8 يونية 2015 م  بالتعاون بين مركز سيداو للديمقراطية وحقوق الانسان والجمعية الوطنية للدفاع عن الحقوق والحريات . \r\nالمشاركة الفعالة فى مؤتمر دور العلم فى مكافحة الارهاب بالجزيرة فى الفترة من 27 /12 الى 30 /12 /2014 م-وزارة الشباب  والمجلس الوطنى للشباب ومجلس علماء مصر\r\n\r\nالمشاركة فى البرنامج التدريبى للاستثمار فى الاوراق المالية بالجزيرة  فى الفترة من 14 /3 /2009 الى 19 / 3 /2009 م –المجلس القومى للشباب . \r\n\r\nالمشاركة فى برنامج التأهيل التربوى للمعلمين من غير خريجى كليات التربية فى الفترة من 27 /7 الى 6 / 8 / 2008 م – جامعة الاسكندرية .\r\nالمشاركة الفعالة فى الملتقى الثقافى الرابع للشباب بمحافظة مطروح  فى الفترة من 1 /3 /2008 الى 7 / 3 / 2008 م –وزارة الثقافة .\r\nالمشاركة الفعالة فى الملتقى الثقافى الثالث للشباب بمدينة العريش فبراير 2007\r\nالمشاركة الفعالة فى دورة التعليم المدنى فى الفترة من 29 /1 الى 7 / 2 /2007 م الشلالات الاسكندرية\r\nالمشاركة الفعالة فى دورة التعليم المدنى خلال الفترة من 14 / 12 الى 16 / 12 /2006 م بالشلالات الاسكندرية \r\nالمشاركة الفعالة فى الملتقى الثقافى الثانى بأسوان –وزارة الثقافة \r\nالمشاركة فى منتدى الحوار الاول  بشرم الشيخ ممثلة عن وزارة الشباب والرياضة \r\n\r\nالمشاركة فى حضور برامج توعية سياسية من خلال مدرية الشباب والرياضة بمطروح .\r\n\r\nالمشاركة فى حملات التوعية بالصحة الانجابية ومواجهة الايدز من خلال جمعية  تنظيم الاسرة .\r\n\r\nعضو مكتب شباب المستقبل – برلمان الشباب – الصالون الثقافى', '8f3744fe46266d5a52b85adc0cd678a9.jpg', NULL, NULL, NULL, 'https://www.facebook.com/doaa.abdo.56?mibextid=ZbWKwL', 'https://x.com/DoaaABDO1068282?t=zmCiNp9c8nPGj_3IgzBchg&s=09', 'https://www.linkedin.com/in/doaa-abdo-518b00240?utm_source=share&utm_campaign=share_via&utm_content=profile&utm_medium=android_app', NULL, 'https://www.linkedin.com/in/doaa-abdo-518b00240?utm_source=share&utm_campaign=share_via&utm_content=profile&utm_medium=android_app', '2024-03-15 23:35:41', 6, 0, NULL, NULL, 'Africa/Cairo', '2024-03-14 14:59:15', '2024-03-20 19:28:54', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
