(990, NULL, 'دكتوره عالية حمدي سليمان', NULL, NULL, '01110140961', NULL, 'قرية العتامنه مركز منفلوط محافظه اسيوط', 'مشرف ميدانى فى مشروع تحويشه ومدرب تثقيف مالى ومدرب مشوره اسريه بالمجلس القومى للمراه ومنسق كافه قرى مركز ومدينه منفلوط  لكافه انشطه  المجلس القومى للمرأه التابع لرئاسه الجمهوريه', '٣٣', NULL, NULL, '5534b8631d416278b66a4773ffcc8e3b.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 6, 0, NULL, 'ipQrbGpYI3ek3x8If4gx6fpyZtyakVQv6z5dXf6IluYkkMbIoHJXn8EXpT3z6cgAZRL7tdRP7w7WOg8SlDj5Q6lvshx41KwLtLMB', NULL, '2024-03-14 17:02:01', '2024-03-15 14:00:24', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 1),
